// Particle Nebula
// Adapted from GenerativeArtGallery / artwork10

let nbPts = [];
let nbAtts = [];
let nbPrevPart = '';
let nbPrevAtt = '';

function nbMakePts(n) {
  let pts = [];
  for (let i = 0; i < n; i++) {
    pts.push({
      x: Math.random() * 400, y: Math.random() * 400,
      vx: (Math.random() - 0.5) * 2, vy: (Math.random() - 0.5) * 2,
      mass: 0.5 + Math.random() * 1.5,
      hue: Math.random() * 360, hist: []
    });
  }
  return pts;
}

function nbMakeAtts(n, massBase) {
  let atts = [];
  for (let i = 0; i < n; i++) {
    atts.push({
      x: 60 + Math.random() * 280, y: 60 + Math.random() * 280,
      mass: massBase * (0.7 + Math.random() * 0.6),
      life: Math.floor(300 + Math.random() * 300),
      maxLife: 450
    });
  }
  return atts;
}

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  nbPts = nbMakePts(200);
  nbAtts = nbMakeAtts(4, 80);
};

p.draw = function() {
  let partStr  = p.getSynthVar('particle_count') || 'medium';
  let attStr   = p.getSynthVar('attractor_count') || 'medium';
  let massStr  = p.getSynthVar('attractor_mass') || 'medium';
  let trailStr = p.getSynthVar('trail_mode') || 'medium';
  let colorStr = p.getSynthVar('color_mode') || 'nebula';

  let partN    = partStr === 'sparse' ? 80 : partStr === 'medium' ? 200 : 380;
  let attN     = attStr === 'few' ? 2 : attStr === 'medium' ? 5 : 8;
  let massBase = massStr === 'light' ? 40 : massStr === 'medium' ? 80 : 160;
  let histLen  = trailStr === 'short' ? 8 : trailStr === 'medium' ? 18 : 38;

  if (partStr !== nbPrevPart) { nbPts = nbMakePts(partN); nbPrevPart = partStr; }
  if (attStr !== nbPrevAtt)   { nbAtts = nbMakeAtts(attN, massBase); nbPrevAtt = attStr; }

  p.background(240, 20, 5, 12);

  // Attractor lifecycle + glow
  for (let i = 0; i < nbAtts.length; i++) {
    let a = nbAtts[i];
    a.life--;
    if (a.life <= 0) {
      nbAtts[i] = {
        x: 60 + Math.random() * 280, y: 60 + Math.random() * 280,
        mass: massBase * (0.7 + Math.random() * 0.6),
        life: Math.floor(300 + Math.random() * 300), maxLife: 450
      };
      a = nbAtts[i];
    }
    let alpha = p.map(a.life, 0, a.maxLife, 0, 35);
    p.noStroke();
    p.fill(220, 35, 80, alpha);
    p.ellipse(a.x, a.y, Math.sqrt(a.mass) * 4, Math.sqrt(a.mass) * 4);
  }

  // Particle physics + trail
  let active = nbPts.slice(0, partN);
  active.forEach(function(pt) {
    let fx = 0, fy = 0;
    nbAtts.forEach(function(a) {
      let dx = a.x - pt.x, dy = a.y - pt.y;
      let raw = Math.sqrt(dx * dx + dy * dy);
      let d   = Math.max(5, Math.min(raw, 30));
      let str = (a.mass * pt.mass) / (d * d);
      fx += dx / (raw + 0.001) * str;
      fy += dy / (raw + 0.001) * str;
    });
    let na = p.noise(pt.x * 0.005, pt.y * 0.005, p.frameCount * 0.002) * p.TWO_PI * 2;
    fx += Math.cos(na) * 0.1;
    fy += Math.sin(na) * 0.1;

    pt.vx = (pt.vx + fx * 0.02) * 0.98;
    pt.vy = (pt.vy + fy * 0.02) * 0.98;
    let spd = Math.sqrt(pt.vx * pt.vx + pt.vy * pt.vy);
    if (spd > 10) { pt.vx = pt.vx / spd * 10; pt.vy = pt.vy / spd * 10; }

    pt.hist.push({ x: pt.x, y: pt.y });
    if (pt.hist.length > histLen) pt.hist.shift();

    pt.x += pt.vx; pt.y += pt.vy;
    if (pt.x < 0 || pt.x > 400) { pt.vx *= -1; pt.x = Math.max(0, Math.min(pt.x, 400)); }
    if (pt.y < 0 || pt.y > 400) { pt.vy *= -1; pt.y = Math.max(0, Math.min(pt.y, 400)); }

    let hue = colorStr === 'nebula'   ? p.map(p.noise(pt.x * 0.008, pt.y * 0.008), 0, 1, 200, 300) :
              colorStr === 'fire'     ? p.map(spd, 0, 10, 0, 50) :
              colorStr === 'ice'      ? p.map(p.noise(pt.x * 0.008, pt.y * 0.008), 0, 1, 170, 220) :
              (pt.hue + 0.15) % 360;
    pt.hue = hue;

    for (let k = 1; k < pt.hist.length; k++) {
      let alpha = p.map(k, 0, pt.hist.length, 4, 60);
      p.stroke(hue, 70, 90, alpha);
      p.strokeWeight(1);
      p.line(pt.hist[k-1].x, pt.hist[k-1].y, pt.hist[k].x, pt.hist[k].y);
    }
  });
};
